import{_ as l,o as t,c as s,ag as a}from"./chunks/framework.Cqf6AMW8.js";const c=JSON.parse('{"title":"CSS 响应式设计","description":"CSS 响应式设计相关知识，包括二倍图、屏幕分辨率、视口和适配原理。","frontmatter":{"title":"CSS 响应式设计","description":"CSS 响应式设计相关知识，包括二倍图、屏幕分辨率、视口和适配原理。","date":"2026-04-21T00:00:00.000Z","tags":["CSS","响应式设计"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/css/CSS-基础-24-响应式设计.md","filePath":"docs/frontend/css/CSS-基础-24-响应式设计.md","lastUpdated":1776715536000}'),n={name:"docs/frontend/css/CSS-基础-24-响应式设计.md"};function o(e,i,r,p,h,d){return t(),s("div",null,[...i[0]||(i[0]=[a('<p>#CSS理论</p><p>======================================================</p><h2 id="_1-二倍图" tabindex="-1">1. 二倍图 <a class="header-anchor" href="#_1-二倍图" aria-label="Permalink to &quot;1. 二倍图&quot;">​</a></h2><ul><li><p><strong>设计参考</strong>：现阶段设计稿参考iPhone6/7/8，设备宽度375px产出设计稿</p></li><li><p><strong>二倍图尺寸</strong>：750px</p></li><li><p><strong>应用场景</strong>：为了在高分辨率屏幕上显示清晰的图像和界面</p></li></ul><p>======================================================</p><h2 id="_2-屏幕分辨率" tabindex="-1">2. 屏幕分辨率 <a class="header-anchor" href="#_2-屏幕分辨率" aria-label="Permalink to &quot;2. 屏幕分辨率&quot;">​</a></h2><ul><li><p><strong>概念</strong>：纵横向上的像素点数，单位是px</p></li><li><p><strong>PC分辨率</strong>：</p><ul><li>1920 * 1080</li><li>1366 * 768</li><li>...</li></ul></li><li><p><strong>缩放比例</strong>：</p><ul><li>缩放150%时： <ul><li>1920 / 150%</li><li>1080 / 150%</li></ul></li></ul></li><li><p><strong>分辨率类型</strong>：</p><ul><li><strong>物理分辨率</strong>：硬件分辨率，出厂设置</li><li><strong>逻辑分辨率</strong>：缩放调节的分辨率，软件/驱动设置</li></ul></li></ul><p>======================================================</p><h2 id="_3-视口" tabindex="-1">3. 视口 <a class="header-anchor" href="#_3-视口" aria-label="Permalink to &quot;3. 视口&quot;">​</a></h2><ul><li><p><strong>概念</strong>：显示HTML网页的区域，用来约束HTML尺寸</p></li><li><p><strong>视口标签</strong>：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">meta</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;viewport&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;width=device-width, initial-scale=1.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></li><li><p><strong>属性说明</strong>：</p><ul><li><strong>width=device-width</strong>：视口宽度 = 设备宽度</li><li><strong>initial-scale=1.0</strong>：缩放1倍（不缩放）</li></ul></li><li><p><strong>作用</strong>：确保网页在不同设备上有正确的显示尺寸</p></li></ul><p>======================================================</p><h2 id="_4-适配原理" tabindex="-1">4. 适配原理 <a class="header-anchor" href="#_4-适配原理" aria-label="Permalink to &quot;4. 适配原理&quot;">​</a></h2><ul><li><p><strong>核心问题</strong>：不同设备的屏幕尺寸和分辨率差异</p></li><li><p><strong>解决方案</strong>：</p><ol><li>使用相对单位（如rem、vw/vh）</li><li>结合媒体查询进行响应式设计</li><li>利用视口标签控制显示区域</li></ol></li><li><p><strong>设计流程</strong>：</p><ol><li>以750px二倍图为设计基础</li><li>转换为实际开发尺寸（375px）</li><li>使用适配方案实现多设备兼容</li></ol></li></ul><p>======================================================</p>',14)])])}const u=l(n,[["render",o]]);export{c as __pageData,u as default};
